import { Stock, HistoricalDataPoint } from '../types';
import { getProxiedUrl } from './proxyHelper';

// Interface for the structure of a single stock object from the TWSE getStockInfo API response
interface TwseStock {
    c: string; // code
    n: string; // name
    z: string; // current price
    v: string; // volume
    o: string; // open
    h: string; // high
    l: string; // low
    y: string; // yesterday's price
}

/**
 * 安全的轉型浮點數，處理 "-", "", "null" 等異常狀況
 */
const safeParseFloat = (val: string | undefined | null, fallback: number = 0): number => {
    if (!val || val === '-' || val === 'null') return fallback;
    const cleaned = val.toString().replace(/,/g, '');
    const parsed = parseFloat(cleaned);
    return isNaN(parsed) ? fallback : parsed;
};

/**
 * Fetches real-time stock data from the Taiwan Stock Exchange (TWSE) API.
 */
export const fetchStockData = async (codes: string[]): Promise<Stock[]> => {
    if (codes.length === 0) {
        return [];
    }

    const query = codes.flatMap(code => [`tse_${code}.tw`, `otc_${code}.tw`]).join('|');
    const apiUrl = `https://mis.twse.com.tw/stock/api/getStockInfo.jsp?ex_ch=${query}&json=1&delay=0&_=${Date.now()}`;

    const proxyUrl = getProxiedUrl(apiUrl);

    try {
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error(`Network response was not ok`);

        const data = await response.json();

        if (!data || !data.msgArray || data.msgArray.length === 0) {
            return [];
        }

        const stocks: Stock[] = data.msgArray.map((item: TwseStock) => {
            const yesterdayPrice = safeParseFloat(item.y, 0);
            // 如果 z (現價) 是 "-", 通常表示尚未成交，此時以昨收價當作參考現價
            const price = safeParseFloat(item.z, yesterdayPrice);
            const open = safeParseFloat(item.o, price);
            const high = safeParseFloat(item.h, price);
            const low = safeParseFloat(item.l, price);
            const volume = safeParseFloat(item.v, 0);

            const change = price - yesterdayPrice;
            const changePercent = yesterdayPrice > 0 ? (change / yesterdayPrice) * 100 : 0;

            return {
                code: item.c,
                name: item.n,
                price: price,
                change: parseFloat(change.toFixed(2)),
                changePercent: parseFloat(changePercent.toFixed(2)),
                open: open,
                high: high,
                low: low,
                volume: Math.floor(volume),
                yesterdayPrice: yesterdayPrice,
            };
        });

        return Array.from(new Map(stocks.map(stock => [stock.code, stock])).values());

    } catch (error) {
        console.error("Failed to fetch stock data:", error);
        throw new Error("無法從證交所獲取資料，請稍後再試。");
    }
};

/**
 * Fetches historical daily stock data.
 */
export const fetchHistoricalData = async (code: string): Promise<HistoricalDataPoint[]> => {
    const today = new Date();
    const dates: Date[] = [];
    for (let i = 0; i < 36; i++) {
        dates.push(new Date(today.getFullYear(), today.getMonth() - i, 1));
    }

    const sources = {
        TSE: {
            getUrl: (year: number, month: string) => `https://www.twse.com.tw/exchangeReport/STOCK_DAY?response=json&date=${year}${month}01&stockNo=${code}`,
            getData: (json: any) => (json.stat === "OK" && Array.isArray(json.data) ? json.data : []),
            getClosePriceIndex: () => 6,
        },
        OTC: {
            getUrl: (rocYear: number, month: string) => `https://www.tpex.org.tw/web/stock/aftertrading/daily_trading_info/st43_result.php?l=zh-tw&d=${rocYear}/${month}&stkno=${code}`,
            getData: (json: any) => (Array.isArray(json.aaData) ? json.aaData : []),
            getClosePriceIndex: () => 6,
        },
        EMERGING: {
            getUrl: (rocYear: number, month: string) => `https://www.tpex.org.tw/web/stock/emergingstock/historical/daily/EMDaily_result.php?l=zh-tw&d=${rocYear}/${month}&stkno=${code}`,
            getData: (json: any) => (Array.isArray(json.aaData) ? json.aaData : []),
            getClosePriceIndex: () => 4,
        }
    };

    let rawData: any[] = [];
    let sourceKey: keyof typeof sources | null = null;

    try {
        for (const key of Object.keys(sources) as Array<keyof typeof sources>) {
            sourceKey = key;
            const currentSource = sources[sourceKey];
            const urls = dates.map(date => {
                const year = date.getFullYear();
                const month = (date.getMonth() + 1).toString().padStart(2, '0');
                const rocYear = year - 1911;
                return currentSource.getUrl(sourceKey === 'TSE' ? year : rocYear, month);
            });

            const responses = await Promise.all(urls.map(url => fetch(getProxiedUrl(url))));
            let combinedData: any[] = [];

            for (const response of responses) {
                if (response.ok) {
                    const json = await response.json();
                    combinedData.push(...currentSource.getData(json));
                }
            }

            if (combinedData.length > 0) {
                rawData = combinedData;
                break;
            } else {
                sourceKey = null;
            }
        }

        if (rawData.length === 0 || !sourceKey) throw new Error('No data');

        const closePriceIndex = sources[sourceKey].getClosePriceIndex();
        const historicalPoints: HistoricalDataPoint[] = rawData
            .map(item => {
                if (Array.isArray(item) && item.length > closePriceIndex) {
                    const date = item[0]?.trim();
                    const closeVal = safeParseFloat(item[closePriceIndex], 0);
                    if (date && closeVal > 0) {
                         return { date, close: closeVal };
                    }
                }
                return null;
            })
            .filter((p): p is HistoricalDataPoint => p !== null);

        const uniquePoints = Array.from(new Map(historicalPoints.map(p => [p.date, p])).values());
        uniquePoints.sort((a, b) => {
            const dateA = new Date(a.date.replace(/(\d+)\/(\d+)\/(\d+)/, (_, y, m, d) => `${parseInt(y) + 1911}-${m}-${d}`));
            const dateB = new Date(b.date.replace(/(\d+)\/(\d+)\/(\d+)/, (_, y, m, d) => `${parseInt(y) + 1911}-${m}-${d}`));
            return dateB.getTime() - dateA.getTime();
        });

        return uniquePoints;

    } catch (error) {
        console.error("Historical data error:", error);
        return [];
    }
};

import React from 'react';

interface SparklineProps {
    data: number[];
    isPositive: boolean;
}

const Sparkline: React.FC<SparklineProps> = ({ data, isPositive }) => {
  // 過濾 NaN 並確保有足夠的數據
  const cleanData = (data || []).filter(val => typeof val === 'number' && !isNaN(val));

  if (cleanData.length < 2) {
    return (
        <div className="flex items-center justify-center w-full h-full">
            <p className="text-[10px] text-secondary-light dark:text-secondary-dark opacity-50">載入中</p>
        </div>
    );
  }

  const color = isPositive ? 'rgba(239, 68, 68, 0.9)' : 'rgba(34, 197, 94, 0.9)';
  const gradientId = `spark-grad-${isPositive ? 'pos' : 'neg'}`;
  const gradientColor = isPositive ? 'rgba(239, 68, 68, 0.2)' : 'rgba(34, 197, 94, 0.2)';

  const svgWidth = 100;
  const svgHeight = 40;
  const padding = 2;

  const maxVal = Math.max(...cleanData);
  const minVal = Math.min(...cleanData);
  const range = maxVal - minVal || 1;

  const points = cleanData.map((d, i) => {
    const x = (i / (cleanData.length - 1)) * svgWidth;
    const y = svgHeight - padding - ((d - minVal) / range) * (svgHeight - padding * 2);
    return `${x},${y}`;
  });

  const path = `M ${points.join(' L ')}`;
  const areaPath = `${path} L ${svgWidth},${svgHeight} L 0,${svgHeight} Z`;

  return (
    <svg viewBox={`0 0 ${svgWidth} ${svgHeight}`} className="w-full h-full" preserveAspectRatio="none">
      <defs>
        <linearGradient id={gradientId} x1="0%" y1="0%" x2="0%" y2="100%">
          <stop offset="0%" style={{ stopColor: gradientColor, stopOpacity: 1 }} />
          <stop offset="100%" style={{ stopColor: gradientColor, stopOpacity: 0 }} />
        </linearGradient>
      </defs>
      <path d={areaPath} fill={`url(#${gradientId})`} />
      <path d={path} fill="none" stroke={color} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" />
    </svg>
  );
};

export default Sparkline;

import React, { useRef, useMemo, useCallback } from 'react';
import { HistoricalDataPoint } from '../types';

interface StockChartProps {
    priceData: HistoricalDataPoint[];
    color?: string;
}

const StockChart: React.FC<StockChartProps> = ({ priceData, color }) => {
    const svgRef = useRef<SVGSVGElement>(null);
    const tooltipGroupRef = useRef<SVGGElement>(null);
    const tooltipLineRef = useRef<SVGLineElement>(null);
    const tooltipCircleRef = useRef<SVGCircleElement>(null);
    const tooltipTextRef = useRef<HTMLDivElement>(null);

    // 清洗數據
    const cleanData = useMemo(() => {
        return (priceData || [])
            .filter(p => p && typeof p.close === 'number' && !isNaN(p.close))
            .reverse(); // 為了繪圖從舊到新
    }, [priceData]);

    if (cleanData.length < 2) {
        return (
            <div className="flex items-center justify-center w-full h-full bg-surface-dark-alt/20 rounded-xl">
                <p className="text-sm text-secondary-dark">暫無歷史價格趨勢</p>
            </div>
        );
    }

    const priceColor = color || (cleanData[cleanData.length - 1].close >= cleanData[0].close ? '#ef4444' : '#22c55e');
    const gradientColor = priceColor.startsWith('#') ? `${priceColor}33` : priceColor.replace('0.9', '0.2');
    const gradientId = `chart-grad-${Math.random().toString(36).substr(2, 9)}`;

    const svgWidth = 400;
    const svgHeight = 150;
    const padding = 10;

    const allValues = cleanData.map(p => p.close);
    const maxVal = Math.max(...allValues);
    const minVal = Math.min(...allValues);
    const range = maxVal - minVal || 1;

    const scaleY = (val: number) => svgHeight - padding - ((val - minVal) / range) * (svgHeight - padding * 2);
    const xStep = svgWidth / (cleanData.length - 1);

    const points = cleanData.map((d, i) => ({
        x: i * xStep,
        y: scaleY(d.close),
        data: d,
    }));

    const pricePath = `M ${points.map(p => `${p.x},${p.y}`).join(' L ')}`;
    const areaPath = `${pricePath} L ${svgWidth},${svgHeight} L 0,${svgHeight} Z`;

    const handleInteraction = useCallback((clientX: number) => {
        if (!svgRef.current || !tooltipGroupRef.current || !tooltipTextRef.current) return;

        const rect = svgRef.current.getBoundingClientRect();
        const svgX = (clientX - rect.left) * (svgWidth / rect.width);
        const index = Math.max(0, Math.min(points.length - 1, Math.round(svgX / xStep)));
        const point = points[index];

        tooltipGroupRef.current.style.opacity = '1';
        tooltipTextRef.current.style.opacity = '1';

        tooltipLineRef.current?.setAttribute('x1', `${point.x}`);
        tooltipLineRef.current?.setAttribute('x2', `${point.x}`);
        tooltipCircleRef.current?.setAttribute('cx', `${point.x}`);
        tooltipCircleRef.current?.setAttribute('cy', `${point.y}`);

        tooltipTextRef.current.innerHTML = `
            <div class="font-mono">
                <div class="text-[10px] text-gray-400">${point.data.date}</div>
                <div class="font-bold text-sm" style="color: ${priceColor}">${point.data.close.toFixed(2)}</div>
            </div>
        `;

        const tipWidth = tooltipTextRef.current.offsetWidth;
        let tipX = (point.x / svgWidth) * rect.width - tipWidth / 2;
        tipX = Math.max(5, Math.min(rect.width - tipWidth - 5, tipX));
        tooltipTextRef.current.style.left = `${tipX}px`;

    }, [points, xStep, priceColor]);

    const hideTooltip = () => {
        if (tooltipGroupRef.current) tooltipGroupRef.current.style.opacity = '0';
        if (tooltipTextRef.current) tooltipTextRef.current.style.opacity = '0';
    };

    return (
        <div className="relative w-full h-full group">
            <svg
                ref={svgRef}
                viewBox={`0 0 ${svgWidth} ${svgHeight}`}
                className="w-full h-full"
                preserveAspectRatio="none"
                onMouseMove={(e) => handleInteraction(e.clientX)}
                onMouseLeave={hideTooltip}
                onTouchMove={(e) => handleInteraction(e.touches[0].clientX)}
                onTouchEnd={hideTooltip}
            >
                <defs>
                  <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor={priceColor} stopOpacity={0.3}/>
                    <stop offset="100%" stopColor={priceColor} stopOpacity={0}/>
                  </linearGradient>
                </defs>

                <path d={areaPath} fill={`url(#${gradientId})`} />
                <path d={pricePath} fill="none" stroke={priceColor} strokeWidth="2.5" strokeLinejoin="round" />

                <g ref={tooltipGroupRef} style={{ opacity: 0, transition: 'opacity 0.2s' }}>
                    <line ref={tooltipLineRef} y1="0" y2={svgHeight} stroke="rgba(255,255,255,0.2)" strokeWidth="1" strokeDasharray="4" />
                    <circle ref={tooltipCircleRef} r="5" fill={priceColor} stroke="#111" strokeWidth="2" />
                </g>
            </svg>

            <div
                ref={tooltipTextRef}
                className="absolute top-0 bg-black/90 border border-white/10 rounded px-2 py-1 pointer-events-none transition-opacity duration-200 shadow-xl z-20"
                style={{ opacity: 0 }}
            ></div>
        </div>
    );
};

