const StockModal: React.FC<StockModalProps> = ({ stock, onClose, onStartAnalysis }) => {
    // Daily change for header display
    const isPositive = stock.change >= 0;
    const priceColor = isPositive ? 'text-positive' : 'text-negative';

    const [isClosing, setIsClosing] = useState(false);

    const [fullHistoricalData, setFullHistoricalData] = useState<HistoricalDataPoint[] | null>(null);
    const [isHistoryLoading, setIsHistoryLoading] = useState(true);
    const [historyError, setHistoryError] = useState<string | null>(null);

    const [activeChartTab, setActiveChartTab] = useState<ChartTab>('即時行情');

    const [activeTab, setActiveTab] = useState<ModalTab>('info');
    const [financialAnalysis, setFinancialAnalysis] = useState<FinancialAnalysis | null>(null);
    const [isFinancialsLoading, setIsFinancialsLoading] = useState(true);
    const [financialsError, setFinancialsError] = useState<string | null>(null);

    const handleClose = useCallback(() => {
        if (isClosing) return;
        setIsClosing(true);
    }, [isClosing]);

    const handleAnimationEnd = (e: React.AnimationEvent) => {
        if (e.target === e.currentTarget && isClosing) {
            onClose();
        }
    };

    const handleAnalysisClick = useCallback(() => {
        onStartAnalysis(stock.name, stock.code);
        handleClose();
    }, [stock, onStartAnalysis, handleClose]);

    useEffect(() => {
        const handleKeyDown = (event: KeyboardEvent) => {
            if (event.key === 'Escape') {
                handleClose();
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [handleClose]);

    useEffect(() => {
        const loadHistoricalData = async () => {
            setIsHistoryLoading(true);
            setHistoryError(null);
            setFullHistoricalData(null);
            try {
                const data = await fetchHistoricalData(stock.code);
                 const todayPoint: HistoricalDataPoint = {
                    date: new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: '2-digit', day: '2-digit' }).replace(/(\d+)\/(\d+)\/(\d+)/, (_, y, m, d) => `${y-1911}/${m}/${d}`), // Format to ROC
                    close: stock.price,
                };

                const combinedData = data ? [todayPoint, ...data.filter(d => d.date !== todayPoint.date)] : [todayPoint];
                setFullHistoricalData(combinedData);

            } catch (err) {
                 if (err instanceof Error) {
                    setHistoryError(err.message);
                } else {
                    setHistoryError('獲取歷史資料時發生未知錯誤。');
                }
            } finally {
                setIsHistoryLoading(false);
            }
        };
        loadHistoricalData();
    }, [stock.code, stock.price]);

    const chartData = useMemo(() => {
        if (!fullHistoricalData) return null;

        switch (activeChartTab) {
            case '即時行情':
                return fullHistoricalData.slice(0, 30);
            case '日線':
                return fullHistoricalData.slice(0, 90);
            case '週線':
                return aggregateToWeekly(fullHistoricalData);
            case '月線':
                return aggregateToMonthly(fullHistoricalData);
            default:
                return fullHistoricalData.slice(0, 30);
        }
    }, [fullHistoricalData, activeChartTab]);

    // Determine chart color based on the selected time range's start and end points.
    const chartColor = useMemo(() => {
        if (!chartData || chartData.length < 2) {
            // Fallback to daily change if not enough data for the range
            return stock.change >= 0 ? '#ef4444' : '#22c55e';
        }
        // Data is sorted newest to oldest. Compare the newest (index 0) with the oldest (last index).
        const latestPrice = chartData[0].close;
        const earliestPrice = chartData[chartData.length - 1].close;
        return latestPrice >= earliestPrice ? '#ef4444' : '#22c55e';
    }, [chartData, stock.change]);


    useEffect(() => {
        const fetchFinancials = async () => {
            if (activeTab !== 'financials') return;

            setIsFinancialsLoading(true);
            setFinancialsError(null);
            try {
                // FIX: Financial analysis now uses internal API key handling.
                const analysis = await getAIFinancialAnalysis(stock.name, stock.code);
                setFinancialAnalysis(analysis);
            } catch (err) {
                if (err instanceof Error) {
                    setFinancialsError(err.message);
                } else {
                    setFinancialsError("無法獲取財務分析資料。");
                }
            } finally {
                setIsFinancialsLoading(false);
            }
        };

        // Only fetch when the tab is activated
        if(activeTab === 'financials' && !financialAnalysis) {
            fetchFinancials();
        }
    }, [activeTab, stock, financialAnalysis]);


    const MainTabButton: React.FC<{tab: ModalTab, label: string}> = ({tab, label}) => (
        <button 
            onClick={() => setActiveTab(tab)}
            className={`w-full px-4 py-2.5 text-sm font-semibold rounded-lg transition-all duration-300 focus:outline-none ${activeTab === tab ? 'bg-brand-orange text-white shadow-lg shadow-brand-orange/20' : 'text-secondary-dark hover:bg-white/5'}`}
        >
            {label}
        </button>
    )

    const ChartTabButton: React.FC<{label: ChartTab}> = ({label}) => {
        const isActive = activeChartTab === label;
        return (
            <button 
                onClick={() => setActiveChartTab(label)}
                className={`relative px-3 py-2 text-sm font-semibold transition-colors duration-200 focus:outline-none ${isActive ? 'text-on-surface-dark' : 'text-secondary-dark hover:text-on-surface-dark'}`}
            >
                {label}
                {isActive && <div className="absolute bottom-0 left-2 right-2 h-0.5 bg-brand-orange rounded-full"></div>}
            </button>
        )
    };

    return (
        <div 
            className="fixed inset-0 bg-black/70 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-backdrop-fade-in"
            style={{ perspective: '2000px' }}
            onClick={handleClose}
            role="dialog"
            aria-modal="true"
            aria-labelledby="stock-modal-title"
        >
            <div 
                className={`bg-background-dark rounded-3xl border border-outline-dark shadow-2xl w-full max-w-lg flex flex-col overflow-hidden backface-hidden dark max-h-[95vh] sm:max-h-[90vh] ${isClosing ? 'animate-flip-out' : 'animate-flip-in'}`}
                style={{ transformStyle: 'preserve-3d' }}
                onClick={(e) => e.stopPropagation()}
                onAnimationEnd={handleAnimationEnd}
            >
                {/* Header */}
                 <div className="p-6">
                    <div className="relative flex items-start justify-between">
                         <div className="flex items-center gap-4">
                            <div className={`flex-shrink-0 w-10 h-10 rounded-full flex items-center justify-center ${isPositive ? 'bg-positive/20' : 'bg-negative/20'}`}>
                               {isPositive ? <ArrowUpIcon className="w-5 h-5 text-positive" /> : <ArrowDownIcon className="w-5 h-5 text-negative" /> }
                            </div>
                            <div>
                                <h2 id="stock-modal-title" className="text-xl font-bold text-on-surface-dark">{stock.name}</h2>
                                <p className="text-sm text-secondary-dark">{stock.code}</p>
                            </div>
                         </div>
                         <button 
                            onClick={handleClose} 
                            className="text-secondary-dark hover:text-on-surface-dark bg-white/5 hover:bg-white/10 rounded-full p-1.5 transition-colors focus:outline-none focus:ring-2 focus:ring-brand-orange z-20"
                            aria-label="關閉視窗"
                        >
                            <CloseIcon className="w-5 h-5" />
                        </button>
                    </div>
                     <div className="text-left mt-4">
                        <p className={`text-5xl font-bold ${priceColor}`}>{stock.price.toFixed(2)}</p>
                        <div className={`text-base font-semibold ${priceColor} mt-1 flex items-center`}>
                            <span>{isPositive ? '▲' : '▼'}</span>
                            <span className="ml-1">{stock.change.toFixed(2)}</span>
                            <span className="ml-2">({stock.changePercent.toFixed(2)}%)</span>
                        </div>
                    </div>
                 </div>

                 <div className="px-6 pb-4">
                    <div className="bg-surface-dark-alt/50 p-1 rounded-xl grid grid-cols-2 gap-1">
                        <MainTabButton tab="info" label="即時行情" />
                        <MainTabButton tab="financials" label="財務簡析" />
                    </div>
                 </div>


                <div className="flex-grow overflow-y-auto modal-scrollbar">
                    {activeTab === 'info' && (
                        <div className="px-6 pb-6 space-y-6">
                            <div className="flex items-center space-x-2 border-b border-outline-dark">
                                <ChartTabButton label="即時行情" />
                                <ChartTabButton label="日線" />
                                <ChartTabButton label="週線" />
                                <ChartTabButton label="月線" />
                            </div>
                            <div className="h-48 -mx-6">
                                {isHistoryLoading ? (
                                    <div className="h-full flex items-center justify-center"><LoadingSpinner/></div>
                                ) : historyError ? (
                                    <div className="h-full flex items-center justify-center"><p className="text-sm text-center text-positive/90 p-2">{historyError}</p></div>
                                ) : (chartData && chartData.length > 1) ? (
                                    <StockChart 
                                        priceData={chartData} 
                                        color={chartColor}
                                    />
                                ) : (
                                    <div className="h-full flex items-center justify-center"><p className="text-sm text-center text-secondary-dark p-2">資料不足，無法繪製圖表</p></div>
                                )}
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <DetailItem label="開盤價" value={stock.open.toFixed(2)} />
                                <DetailItem label="最高價" value={stock.high.toFixed(2)} className="text-positive" />
                                <DetailItem label="最低價" value={stock.low.toFixed(2)} className="text-negative" />
                                <DetailItem label="昨收價" value={stock.yesterdayPrice.toFixed(2)} />
                            </div>
                        </div>
                    )}
                    {activeTab === 'financials' && (
                        <FinancialAnalysisView 
                            stockCode={stock.code}
                            isLoading={isFinancialsLoading}
                            error={financialsError}
                            analysis={financialAnalysis}
                        />
                    )}
                </div>

                {/* AI Analysis Button Footer */}
                <div className="p-6 border-t border-outline-dark mt-auto shrink-0">
                    <button
                        onClick={handleAnalysisClick}
                        className="w-full flex justify-center items-center gap-2 bg-primary hover:bg-primary/90 text-on-primary font-bold py-3 px-4 rounded-lg transition-all duration-300 transform hover:scale-105"
                    >
                        <SparklesIcon className="w-5 h-5" />
                        <span>一鍵 AI 新聞分析</span>
                    </button>
                </div>
            </div>
        </div>
    );
};

export default StockModal;

import React, { useState, useCallback } from 'react';
import { generateSimulation } from '../services/geminiService';
import { SimulationResult, UserProfile } from '../types';

const LoadingIcon: React.FC<React.SVGProps<SVGSVGElement>> = ({ className, ...props }) => (
    <svg className={`animate-spin ${className}`} xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" {...props}>
        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
    </svg>
);

const UserInput: React.FC<{
    label: string;
    profile: UserProfile;
    setProfile: (p: UserProfile) => void;
    color: string;
}> = ({ label, profile, setProfile, color }) => (
    <div className={`p-6 rounded-2xl border bg-surface-light dark:bg-surface-dark border-outline-light dark:border-outline-dark shadow-xl space-y-4`}>
        <div className="flex items-center gap-2 mb-2">
            <div className={`w-3 h-8 rounded-full ${color}`}></div>
            <h3 className="text-xl font-bold">{label}</h3>
        </div>
        <div>
            <label className="block text-xs font-semibold text-secondary-dark mb-1 uppercase tracking-wider">暱稱</label>
            <input
                type="text"
                value={profile.name}
                onChange={(e) => setProfile({ ...profile, name: e.target.value })}
                className="w-full px-4 py-2 bg-background-light dark:bg-background-dark border border-outline-light dark:border-outline-dark rounded-lg focus:ring-2 focus:ring-primary/50 outline-none transition"
                placeholder="例如：王小明"
            />
        </div>
        <div>
            <label className="block text-xs font-semibold text-secondary-dark mb-1 uppercase tracking-wider">性格 (MBTI / 關鍵字)</label>
            <input
                type="text"
                value={profile.personality}
                onChange={(e) => setProfile({ ...profile, personality: e.target.value })}
                className="w-full px-4 py-2 bg-background-light dark:bg-background-dark border border-outline-light dark:border-outline-dark rounded-lg focus:ring-2 focus:ring-primary/50 outline-none transition"
                placeholder="例如：INTJ, 冷靜, 控制狂"
            />
        </div>
        <div>
            <label className="block text-xs font-semibold text-secondary-dark mb-1 uppercase tracking-wider">興趣與愛好</label>
            <input
                type="text"
                value={profile.interests}
                onChange={(e) => setProfile({ ...profile, interests: e.target.value })}
                className="w-full px-4 py-2 bg-background-light dark:bg-background-dark border border-outline-light dark:border-outline-dark rounded-lg focus:ring-2 focus:ring-primary/50 outline-none transition"
                placeholder="例如：黑膠唱片, 登山"
            />
        </div>
        <div>
            <label className="block text-xs font-semibold text-secondary-dark mb-1 uppercase tracking-wider">最受不了的事 (雷區)</label>
            <input
                type="text"
                value={profile.petPeeves}
                onChange={(e) => setProfile({ ...profile, petPeeves: e.target.value })}
                className="w-full px-4 py-2 bg-background-light dark:bg-background-dark border border-outline-light dark:border-outline-dark rounded-lg focus:ring-2 focus:ring-primary/50 outline-none transition"
                placeholder="例如：遲到, 咀嚼聲"
            />
        </div>
    </div>
);

// FIX: Removed apiKey prop as per guidelines; API key is now handled internally in the service via process.env.API_KEY.
const FutureSimulatorView: React.FC = () => {
    const [userA, setUserA] = useState<UserProfile>({ name: '', personality: '', interests: '', petPeeves: '' });
    const [userB, setUserB] = useState<UserProfile>({ name: '', personality: '', interests: '', petPeeves: '' });
    const [result, setResult] = useState<SimulationResult | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const handleSimulate = useCallback(async () => {
        if (!userA.name || !userB.name) {
            setError('請填寫雙方的暱稱。');
            return;
        }

        setIsLoading(true);
        setError(null);
        try {
            // FIX: Removed apiKey argument as it's now handled internally in the service.
            const simResult = await generateSimulation(userA, userB);
            setResult(simResult);
        } catch (err) {
            setError(err instanceof Error ? err.message : '模擬失敗，請重試。');
        } finally {
            setIsLoading(false);
        }
    }, [userA, userB]);

    const renderScore = (score: number) => {
        const colorClass = score > 80 ? 'text-positive' : score > 50 ? 'text-brand-gold' : 'text-negative';
        return (
            <div className="flex flex-col items-center justify-center p-6 bg-surface-dark-alt/50 rounded-2xl border border-outline-dark">
                <span className="text-sm font-bold text-secondary-dark mb-2 uppercase tracking-widest">契合度評分</span>
                <div className={`text-6xl font-black ${colorClass}`}>{score}</div>
                <div className="w-full bg-background-dark rounded-full h-2 mt-4 overflow-hidden">
                    <div className={`h-full ${colorClass.replace('text', 'bg')} transition-all duration-1000`} style={{ width: `${score}%` }}></div>
                </div>
            </div>
        );
    };

    return (
        <div className="max-w-6xl mx-auto space-y-8 animate-fade-in">
            <div className="text-center space-y-2">
                <h2 className="text-4xl font-black text-on-background-light dark:text-on-background-dark tracking-tighter">未來模擬劇本生成器</h2>
                <p className="text-secondary-light dark:text-secondary-dark max-w-2xl mx-auto">
                    輸入兩人的性格特徵，讓 AI 穿越時空，模擬你們在極端情境下的化學反應。
                </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <UserInput label="用戶 A" profile={userA} setProfile={setUserA} color="bg-primary" />
                <UserInput label="用戶 B" profile={userB} setProfile={setUserB} color="bg-blue-500" />
            </div>

            <div className="flex justify-center">
                <button
                    onClick={handleSimulate}
                    disabled={isLoading}
                    className="group relative px-12 py-4 bg-primary text-on-primary rounded-full font-bold text-xl shadow-glow-orange hover:scale-105 active:scale-95 transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed overflow-hidden"
                >
                    <span className="relative z-10 flex items-center gap-3">
                        {isLoading ? <><LoadingIcon className="w-6 h-6" /> 運算未來中...</> : '啟動未來模擬器'}
                    </span>
                    <div className="absolute inset-0 bg-white/20 transform translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                </button>
            </div>

            {error && (
                <div className="bg-positive/10 border border-positive/30 text-positive p-4 rounded-xl text-center animate-shake">
                    {error}
                </div>
            )}

            {result && !isLoading && (
                <div className="mt-12 space-y-12 animate-slide-up-fade">
                    <div className="p-8 bg-surface-light dark:bg-surface-dark rounded-3xl border border-outline-light dark:border-outline-dark shadow-2xl">
                        <div className="inline-block px-4 py-1 bg-primary/10 text-primary text-xs font-bold rounded-full mb-4 uppercase tracking-widest">模擬情境</div>
                        <h3 className="text-3xl font-black mb-2">{result.scenario_title}</h3>
                        <p className="text-secondary-light dark:text-secondary-dark italic border-l-4 border-primary/30 pl-4 py-1 mb-8">
                            {result.setting}
                        </p>

                        <div className="space-y-6">
                            {result.script.map((item, index) => (
                                <div 
                                    key={index} 
                                    className={`flex flex-col ${item.speaker === userA.name ? 'items-start' : 'items-end'} animate-stagger-in`}
                                    style={{ animationDelay: `${index * 150}ms` }}
                                >
                                    <div className={`max-w-[80%] space-y-1 ${item.speaker === userA.name ? 'text-left' : 'text-right'}`}>
                                        <div className="flex items-center gap-2 mb-1 justify-inherit">
                                            <span className="text-xs font-black uppercase text-secondary-dark tracking-tighter">{item.speaker}</span>
                                            <span className="px-2 py-0.5 bg-background-light dark:bg-background-dark text-[10px] rounded border border-outline-light dark:border-outline-dark">{item.mood}</span>
                                        </div>
                                        <div className={`p-4 rounded-2xl shadow-sm ${
                                            item.speaker === userA.name 
                                            ? 'bg-primary/5 dark:bg-primary/20 border-l-4 border-primary rounded-tl-none' 
                                            : 'bg-blue-500/5 dark:bg-blue-500/20 border-r-4 border-blue-500 rounded-tr-none'
                                        }`}>
                                            <p className="text-on-surface-light dark:text-on-surface-dark leading-relaxed font-medium">
                                                「{item.text}」
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                        <div className="lg:col-span-2 p-8 bg-surface-light dark:bg-surface-dark rounded-3xl border border-outline-light dark:border-outline-dark shadow-xl">
                            <h4 className="text-xl font-bold mb-4 flex items-center gap-2">
                                <span className="text-primary">✦</span> 命運點評
                            </h4>
                            <p className="text-on-surface-light dark:text-on-surface-dark leading-relaxed text-lg">
                                {result.psychological_insight}
                            </p>

                            <div className="mt-8 pt-6 border-t border-outline-light dark:border-outline-dark">
                                <h5 className="text-sm font-bold text-secondary-dark mb-3 uppercase tracking-widest">破冰討論題目</h5>
                                <div className="p-4 bg-background-light dark:bg-background-dark rounded-xl border border-dashed border-outline-light dark:border-outline-dark text-center font-bold">
                                    "{result.discussion_topic}"
                                </div>
                            </div>
                        </div>
                        {renderScore(result.compatibility_score)}
                    </div>
                </div>
            )}
        </div>
    );
};

export default React.memo(FutureSimulatorView);
